00244	// (borrowed from Caffe: https://github.com/BVLC/caffe/blob/master/src/caffe/util/im2col.cpp)
00245	// Loops for fast unfold + copy
00246	void im2col(const npy_double* data_im, const int channels,
00247	    const int height, const int width, const int kernel_h, const int kernel_w,
00248	    const int pad_h, const int pad_w,
00249	    const int stride_h, const int stride_w,
00250	    npy_double* data_col) {
00251	  int height_col = (height + 2 * pad_h - kernel_h) / stride_h + 1;
00252	  int width_col = (width + 2 * pad_w - kernel_w) / stride_w + 1;
00253	  int channels_col = channels * kernel_h * kernel_w;
00254	  for (int c = 0; c < channels_col; ++c) {
00255	    int w_offset = c % kernel_w;
00256	    int h_offset = (c / kernel_w) % kernel_h;
00257	    int c_im = c / kernel_h / kernel_w;
00258	    for (int h = 0; h < height_col; ++h) {
00259	      for (int w = 0; w < width_col; ++w) {
00260	        int h_pad = h * stride_h - pad_h + h_offset;
00261	        int w_pad = w * stride_w - pad_w + w_offset;
00262	        if (h_pad >= 0 && h_pad < height && w_pad >= 0 && w_pad < width)
00263	          data_col[(npy_intp)(c * height_col + h) * width_col + w] =
00264	            data_im[(npy_intp)(c_im * height + h_pad) * width + w_pad];
00265	        else
00266	          data_col[(npy_intp)(c * height_col + h) * width_col + w] = 0.;
00267	      }
00268	    }
00269	  }
00270	}
